<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Bouncing Ball Playground</title>
  <style>
    :root {
      color-scheme: dark;
      --bg: #0b1020;
      --panel: #141b31;
      --line: #2a365c;
      --text: #eaf0ff;
      --muted: #98a8ce;
      --accent: #77aaff;
    }

    * { box-sizing: border-box; }

    body {
      margin: 0;
      min-height: 100vh;
      display: grid;
      place-items: center;
      background:
        radial-gradient(circle at 50% 15%, #1c2a52 0%, transparent 42%),
        var(--bg);
      color: var(--text);
      font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    main {
      width: 800px;
      padding: 20px;
      text-align: center;
    }

    h1 {
      margin: 0 0 8px;
      font-size: 1.35rem;
      letter-spacing: 0.04em;
    }

    p {
      margin: 0 0 16px;
      color: var(--muted);
      font-size: 0.95rem;
    }

    .canvas-wrap {
      display: inline-block;
      padding: 10px;
      background: linear-gradient(145deg, #1d294b, #10172b);
      border: 1px solid var(--line);
      border-radius: 18px;
      box-shadow: 0 20px 55px rgba(0, 0, 0, 0.42);
    }

    canvas {
      display: block;
      width: 760px;
      height: 520px;
      background:
        linear-gradient(rgba(255,255,255,0.025) 1px, transparent 1px),
        linear-gradient(90deg, rgba(255,255,255,0.025) 1px, transparent 1px),
        #090e1d;
      background-size: 32px 32px;
      border-radius: 10px;
      cursor: crosshair;
    }

    .controls {
      display: flex;
      justify-content: center;
      gap: 10px;
      margin-top: 15px;
    }

    button {
      appearance: none;
      border: 1px solid #3a4e82;
      border-radius: 9px;
      padding: 9px 16px;
      min-width: 92px;
      color: var(--text);
      background: #1b294d;
      font: inherit;
      font-weight: 650;
      cursor: pointer;
      transition: transform 120ms ease, background 120ms ease;
    }

    button:hover {
      background: #29427b;
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px);
    }

    #clear {
      background: #34213a;
      border-color: #69436f;
    }

    #clear:hover {
      background: #513058;
    }

    @media (max-width: 820px) {
      body { overflow-x: auto; }
    }
  </style>
</head>
<body>
  <main>
    <h1>Bouncing Ball Playground</h1>
    <p>Click anywhere inside the arena to drop a ball.</p>

    <div class="canvas-wrap">
      <canvas id="sim" width="760" height="520" aria-label="Bouncing ball simulation"></canvas>
    </div>

    <div class="controls">
      <button id="drop" type="button">Drop ball</button>
      <button id="play" type="button">Play</button>
      <button id="clear" type="button">Clear</button>
    </div>
  </main>

  <script>
    (() => {
      const canvas = document.getElementById("sim");
      const ctx = canvas.getContext("2d");
      const dropButton = document.getElementById("drop");
      const playButton = document.getElementById("play");
      const clearButton = document.getElementById("clear");

      const w = canvas.width;
      const h = canvas.height;
      const gravity = 0.42;
      const restitution = 0.78;
      const balls = [];
      let playing = false;
      let lastTime = 0;

      function clamp(value, min, max) {
        return Math.max(min, Math.min(max, value));
      }

      function ballColor(index) {
        const hues = [205, 278, 342, 42, 152, 12];
        return hues[index % hues.length];
      }

      function draw() {
        ctx.clearRect(0, 0, w, h);

        for (let i = 0; i < balls.length; i++) {
          const b = balls[i];
          const hue = ballColor(i);

          const glow = ctx.createRadialGradient(
            b.x - b.r * 0.35, b.y - b.r * 0.4, b.r * 0.08,
            b.x, b.y, b.r * 1.35
          );
          glow.addColorStop(0, `hsla(${hue}, 100%, 87%, 1)`);
          glow.addColorStop(0.32, `hsla(${hue}, 95%, 62%, 1)`);
          glow.addColorStop(1, `hsla(${hue}, 88%, 42%, 1)`);

          ctx.beginPath();
          ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
          ctx.fillStyle = glow;
          ctx.shadowColor = `hsla(${hue}, 100%, 65%, 0.55)`;
          ctx.shadowBlur = 16;
          ctx.fill();

          ctx.shadowBlur = 0;
          ctx.lineWidth = 1.5;
          ctx.strokeStyle = `hsla(${hue}, 100%, 92%, 0.5)`;
          ctx.stroke();
        }

        ctx.fillStyle = "rgba(218, 231, 255, 0.55)";
        ctx.font = "12px system-ui, sans-serif";
        ctx.fillText(`${balls.length} ball${balls.length === 1 ? "" : "s"}`, 14, 22);
      }

      function resolveWalls(b) {
        if (b.x - b.r < 0) {
          b.x = b.r;
          if (b.vx < 0) b.vx = -b.vx * restitution;
        } else if (b.x + b.r > w) {
          b.x = w - b.r;
          if (b.vx > 0) b.vx = -b.vx * restitution;
        }

        if (b.y - b.r < 0) {
          b.y = b.r;
          if (b.vy < 0) b.vy = -b.vy * restitution;
        } else if (b.y + b.r > h) {
          b.y = h - b.r;
          if (b.vy > 0) {
            b.vy = -b.vy * restitution;
            if (Math.abs(b.vy) < 0.22) b.vy = 0;
          }
        }
      }

      function addBall(x, y, vx = 0, vy = 0, r = 16) {
        r = Number.isFinite(Number(r)) ? Number(r) : 16;
        r = clamp(Math.abs(r), 2, Math.min(w, h) / 2);

        const b = {
          x: clamp(Number(x) || 0, r, w - r),
          y: clamp(Number(y) || 0, r, h - r),
          vx: Number(vx) || 0,
          vy: Number(vy) || 0,
          r
        };

        balls.push(b);
        draw();
        return { ...b };
      }

      function clear() {
        balls.length = 0;
        draw();
      }

      function step(dt = 1) {
        dt = Number(dt);
        if (!Number.isFinite(dt) || dt <= 0) {
          draw();
          return;
        }

        // Small substeps make edge collisions reliable even with larger dt values.
        const substeps = Math.max(1, Math.ceil(dt / 0.25));
        const subDt = dt / substeps;

        for (let s = 0; s < substeps; s++) {
          for (const b of balls) {
            b.vy += gravity * subDt;
            b.x += b.vx * subDt;
            b.y += b.vy * subDt;
            resolveWalls(b);
          }
        }

        draw();
      }

      window.sim = {
        w,
        h,
        balls: () => balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })),
        addBall,
        clear,
        step
      };

      function animationFrame(time) {
        if (playing) {
          const elapsed = lastTime ? Math.min(50, time - lastTime) : 16.67;
          step(elapsed / 16.67);
          lastTime = time;
        }
        requestAnimationFrame(animationFrame);
      }

      canvas.addEventListener("click", event => {
        const rect = canvas.getBoundingClientRect();
        const x = (event.clientX - rect.left) * (w / rect.width);
        const y = (event.clientY - rect.top) * (h / rect.height);
        addBall(x, y, (Math.random() - 0.5) * 5, -1.5, 14 + Math.random() * 9);
      });

      dropButton.addEventListener("click", () => {
        addBall(
          w * (0.25 + Math.random() * 0.5),
          42,
          (Math.random() - 0.5) * 5,
          0,
          14 + Math.random() * 8
        );
      });

      playButton.addEventListener("click", () => {
        playing = !playing;
        lastTime = 0;
        playButton.textContent = playing ? "Pause" : "Play";
      });

      clearButton.addEventListener("click", clear);

      draw();
      requestAnimationFrame(animationFrame);
    })();
  </script>
</body>
</html>
